    }

    /// Sync entry to inbox
    pub async fn sync_to_inbox(
        &self,
        entry: &MemoryEntry,
    ) -> Result<PathBuf, std::io::Error> {
        let filename = format!("{}.md", sanitize_filename(&entry.title));
